import React, { useState, useEffect, useMemo } from 'react';
import { Navbar } from './components/Navbar';
import { ModuleCard } from './components/ModuleCard';
import { MODULES_DATA } from './constants';
import { SearchIcon, BackIcon, FileIcon, DownloadIcon, ShareIcon } from './components/Icons';
import { Module, ResourceType } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'home' | 'modules' | 'detail'>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');

  // Simple routing simulation using state
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#/modules') {
        setCurrentView('modules');
      } else if (hash.startsWith('#/module/')) {
        const moduleId = hash.split('/').pop();
        const module = MODULES_DATA.find(m => m.id === moduleId);
        if (module) {
          setSelectedModule(module);
          setCurrentView('detail');
        } else {
          setCurrentView('home');
        }
      } else {
        setCurrentView('home');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange(); // Initial check

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const navigateTo = (path: string) => {
    window.location.hash = path;
  };

  const filteredModules = useMemo(() => {
    return MODULES_DATA.filter(m => 
      m.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      m.code.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery]);

  const filteredResources = useMemo(() => {
    if (!selectedModule) return [];
    return selectedModule.resources.filter(r => 
      filterType === 'All' || r.type === filterType
    );
  }, [selectedModule, filterType]);

  const handleShare = (resourceName: string) => {
    if (navigator.share) {
      navigator.share({
        title: `GAKA Resource: ${resourceName}`,
        text: `Check out this academic resource for ${selectedModule?.code}`,
        url: window.location.href,
      }).catch(console.error);
    } else {
      navigator.clipboard.writeText(window.location.href);
      alert('Link copied to clipboard!');
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar />

      <main className="flex-grow container mx-auto max-w-7xl px-4 py-8 sm:px-8">
        {currentView === 'home' && (
          <div className="animate-fade-in flex flex-col items-center text-center py-12 lg:py-24">
            <h2 className="text-4xl sm:text-6xl font-black text-slate-900 mb-6 max-w-3xl leading-[1.1]">
              Centralized Academic <span className="gradient-text">Excellence</span> for CS Students
            </h2>
            <p className="text-lg text-slate-500 max-w-xl mb-10 font-medium">
              Access lecture notes and past examination papers instantly. No login, no registration, just learning.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
              <button 
                onClick={() => navigateTo('#/modules')}
                className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl shadow-indigo-100 hover:bg-indigo-700 hover:scale-[1.02] transition-all"
              >
                Browse Modules
              </button>
              <button className="px-8 py-4 bg-white text-slate-700 border border-slate-200 rounded-2xl font-bold hover:bg-slate-50 transition-all">
                About GAKA
              </button>
            </div>

            <div className="mt-20 grid grid-cols-2 md:grid-cols-4 gap-8 w-full max-w-4xl">
              {[
                { label: 'Modules', value: '8' },
                { label: 'Resources', value: '50+' },
                { label: 'Downloads', value: '1.2k' },
                { label: 'Active Users', value: '300+' }
              ].map((stat, i) => (
                <div key={i} className="flex flex-col items-center">
                  <span className="text-3xl font-black text-slate-900">{stat.value}</span>
                  <span className="text-xs text-slate-400 font-bold uppercase tracking-widest">{stat.label}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentView === 'modules' && (
          <div className="animate-fade-in">
            <div className="flex flex-col md:flex-row md:items-end justify-between mb-10 gap-6">
              <div>
                <h2 className="text-3xl font-black text-slate-900 mb-2">Modules Overview</h2>
                <p className="text-slate-500 font-medium">UQF8 – Third Year, Semester I</p>
              </div>

              <div className="relative w-full md:w-80">
                <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input 
                  type="text" 
                  placeholder="Search module code or name..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 outline-none transition-all shadow-sm"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredModules.map((module) => (
                <ModuleCard 
                  key={module.id} 
                  module={module} 
                  onClick={() => navigateTo(`#/module/${module.id}`)} 
                />
              ))}
              {filteredModules.length === 0 && (
                <div className="col-span-full py-20 text-center text-slate-400 bg-white rounded-3xl border-2 border-dashed border-slate-100">
                  No modules found matching "{searchQuery}"
                </div>
              )}
            </div>
          </div>
        )}

        {currentView === 'detail' && selectedModule && (
          <div className="animate-fade-in max-w-4xl mx-auto">
            <button 
              onClick={() => navigateTo('#/modules')}
              className="flex items-center text-slate-500 font-bold text-sm mb-6 hover:text-indigo-600 transition-colors group"
            >
              <BackIcon className="mr-2 w-5 h-5 group-hover:-translate-x-1 transition-transform" />
              Back to Modules
            </button>

            <div className="bg-gradient-to-br from-indigo-600 to-blue-600 p-8 sm:p-12 rounded-[2rem] text-white shadow-2xl shadow-indigo-200 mb-8 relative overflow-hidden">
              <div className="relative z-10">
                <span className="inline-block bg-white/20 backdrop-blur-md px-3 py-1 rounded-full text-xs font-black tracking-widest uppercase mb-4">
                  {selectedModule.code}
                </span>
                <h2 className="text-3xl sm:text-4xl font-black mb-4 leading-tight">{selectedModule.name}</h2>
                <p className="text-indigo-100 text-lg max-w-2xl font-medium leading-relaxed">
                  {selectedModule.description}
                </p>
              </div>
              <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 -rotate-45 translate-x-32 -translate-y-10 rounded-3xl pointer-events-none"></div>
            </div>

            <div className="bg-white rounded-[2rem] p-6 sm:p-8 shadow-sm border border-slate-100">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                <h3 className="text-xl font-bold text-slate-900">Academic Resources</h3>
                <div className="flex bg-slate-50 p-1 rounded-xl">
                  {['All', 'Notes', 'Past Paper'].map((type) => (
                    <button
                      key={type}
                      onClick={() => setFilterType(type as any)}
                      className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
                        filterType === type 
                        ? 'bg-white text-indigo-600 shadow-sm' 
                        : 'text-slate-500 hover:text-slate-700'
                      }`}
                    >
                      {type === 'Past Paper' ? 'GAKA' : type}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                {filteredResources.map((file) => (
                  <div key={file.id} className="group flex items-center justify-between p-4 bg-slate-50 hover:bg-indigo-50/50 border border-transparent hover:border-indigo-100 rounded-2xl transition-all">
                    <div className="flex items-center space-x-4">
                      <div className={`p-3 rounded-xl ${file.type === 'Notes' ? 'bg-blue-100 text-blue-600' : 'bg-orange-100 text-orange-600'}`}>
                        <FileIcon />
                      </div>
                      <div>
                        <h4 className="font-bold text-slate-800 group-hover:text-indigo-900 transition-colors">{file.name}</h4>
                        <div className="flex items-center text-xs text-slate-400 font-semibold space-x-3 mt-1">
                          <span className="flex items-center">
                            {file.size}
                          </span>
                          <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                          <span>{file.uploadDate}</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center space-x-2">
                      <button 
                        onClick={() => handleShare(file.name)}
                        className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-xl transition-all"
                        title="Share link"
                      >
                        <ShareIcon />
                      </button>
                      <a 
                        href={file.driveUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center space-x-2 px-5 py-3 bg-white text-indigo-600 font-bold text-sm border border-indigo-100 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm"
                      >
                        <DownloadIcon />
                        <span className="hidden sm:inline">Download</span>
                      </a>
                    </div>
                  </div>
                ))}

                {filteredResources.length === 0 && (
                  <div className="py-12 text-center text-slate-400">
                    No resources available for this category yet.
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-100 py-10 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-8 text-center">
          <p className="text-slate-400 text-sm font-medium">
            &copy; {new Date().getFullYear()} GAKA Academic Portal. Mbeya University of Science and Technology (MUST).
          </p>
          <div className="mt-4 flex justify-center space-x-6 text-xs font-bold uppercase tracking-widest text-slate-300">
            <span className="hover:text-indigo-400 cursor-pointer transition-colors">Contact</span>
            <span className="hover:text-indigo-400 cursor-pointer transition-colors">Privacy</span>
            <span className="hover:text-indigo-400 cursor-pointer transition-colors">Terms</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

