import { Module, ResourceType, AcademicFile } from './types';
import { MODULES_DATA } from './constants';

/**
 * INSTRUCTIONS: 
 * 1. Open your Google Sheet.
 * 2. Go to File > Share > Publish to the web.
 * 3. Select 'Entire Document' and 'Comma-separated values (.csv)'.
 * 4. Copy the ID from the URL (the part between /d/ and /pub).
 * 5. Paste it below.
 */
const SHEET_ID = 'YOUR_SHEET_ID_HERE'; 
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/pub?output=csv`;

const App: React.FC = () => {
  const [modules, setModules] = useState<Module[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'modules' | 'detail'>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');

  // Fetch and parse Google Sheet data
  useEffect(() => {
    const fetchData = async () => {
      // If the ID is still the placeholder, use local constants to avoid "Failed to fetch"
      if (SHEET_ID === 'YOUR_SHEET_ID_HERE') {
        console.warn("GAKA: Google Sheet ID not provided. Using local fallback data.");
        setModules(MODULES_DATA);
        setIsLoading(false);
        return;
      }

      try {
        setIsLoading(true);
        const response = await fetch(CSV_URL);
        if (!response.ok) throw new Error('Could not connect to Google Sheets. Verify the sheet is published to the web.');

        const csvText = await response.text();
        // Robust CSV splitting to handle quotes and potential empty rows
        const rows = csvText.split(/\r?\n/).filter(row => row.trim() !== "").slice(1); 

        const groupedModules: Record<string, Module> = {};

        rows.forEach((row, index) => {
          // A slightly better CSV split that respects simple quoted values
          const parts = row.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(val => val?.trim().replace(/^"|"$/g, ''));
          const [moduleCode, moduleName, type, title, viewUrl, downloadUrl] = parts;

          if (!moduleCode || !moduleName) return;

          if (!groupedModules[moduleCode]) {
            groupedModules[moduleCode] = {
              id: moduleCode.toLowerCase().replace(/\s+/g, '-'),
              code: moduleCode,
              name: moduleName,
              description: `Comprehensive academic resources for ${moduleName} (${moduleCode}).`,
              resources: []
            };
          }

          const resource: AcademicFile = {
            id: `${moduleCode}-${index}`,
            name: title || 'Untitled Resource',
            type: (type?.toLowerCase().includes('note')) ? 'Notes' : 'Past Paper',
            driveUrl: downloadUrl || viewUrl || '#',
            size: '---'
          };

          groupedModules[moduleCode].resources.push(resource);
        });

        const modulesArray = Object.values(groupedModules);
        if (modulesArray.length === 0) {
           throw new Error("No valid data found in the spreadsheet.");
        }

        setModules(modulesArray);
        setError(null);
      } catch (err) {
        console.error("GAKA Fetch error:", err);
        setError(err instanceof Error ? err.message : 'An unexpected error occurred');
        // Fallback to local data on error so the app is still usable
        setModules(MODULES_DATA);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  // Sync state with URL hash
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#/modules') {
        setCurrentView('modules');
      } else if (hash.startsWith('#/module/')) {
        const moduleId = hash.split('/').pop();
        const module = modules.find(m => m.id === moduleId);
        if (module) {
          setSelectedModule(module);
          setCurrentView('detail');
        } else if (modules.length > 0) {
          // If modules are loaded but ID is wrong, go back
          setCurrentView('modules');
        }
      } else {
        setCurrentView('home');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange(); // Run on mount/update of modules

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [modules]);

  const navigateTo = (path: string) => {
    window.location.hash = path;
  };

  const filteredModules = useMemo(() => {
    return modules.filter(m => 
      m.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      m.code.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [modules, searchQuery]);

  const filteredResources = useMemo(() => {
    if (!selectedModule) return [];
    return selectedModule.resources.filter(r => 
      filterType === 'All' || r.type === filterType
    );
  }, [selectedModule, filterType]);

  const handleShare = (resourceName: string) => {
    if (navigator.share) {
      navigator.share({
        title: `GAKA: ${resourceName}`,
        text: `Resource for ${selectedModule?.code}`,
        url: window.location.href,
      }).catch(console.error);
    } else {
      navigator.clipboard.writeText(window.location.href);
      alert('Link copied to clipboard!');
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center space-y-6 bg-slate-50">
        <div className="relative">
          <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center font-black text-indigo-600">G</div>
        </div>
        <div className="text-center">
          <p className="text-slate-900 font-bold text-lg animate-pulse">Syncing GAKA Resources</p>
          <p className="text-slate-400 text-sm">Please wait a moment...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc]">
      <Navbar />

      <main className="flex-grow container mx-auto max-w-7xl px-4 py-8 sm:px-8">
        {error && SHEET_ID !== 'YOUR_SHEET_ID_HERE' && (
          <div className="mb-8 p-4 bg-amber-50 border border-amber-200 rounded-2xl text-amber-800 text-sm font-medium flex items-center justify-between">
            <p>Showing offline/backup data. Fetch failed: {error}</p>
            <button onClick={() => window.location.reload()} className="underline font-bold">Retry</button>
          </div>
        )}

        {currentView === 'home' && (
          <div className="animate-fade-in flex flex-col items-center text-center py-12 lg:py-24">
            <div className="inline-block px-4 py-1.5 mb-6 rounded-full bg-indigo-50 text-indigo-600 text-xs font-black tracking-widest uppercase">
              UQF8 Semester I Hub
            </div>
            <h2 className="text-4xl sm:text-7xl font-black text-slate-900 mb-8 max-w-4xl leading-[1.05]">
              The <span className="gradient-text">Academic Engine</span> for CS Excellence
            </h2>
            <p className="text-lg sm:text-xl text-slate-500 max-w-2xl mb-12 font-medium leading-relaxed">
              Instant access to lecture notes, past papers, and study guides. 
              Built by students, for students. No logins, just speed.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
              <button 
                onClick={() => navigateTo('#/modules')}
                className="px-10 py-5 bg-indigo-600 text-white rounded-[1.5rem] font-bold shadow-2xl shadow-indigo-200 hover:bg-indigo-700 hover:scale-[1.02] transition-all duration-300"
              >
                Browse All Modules
              </button>
              <button className="px-10 py-5 bg-white text-slate-700 border border-slate-200 rounded-[1.5rem] font-bold hover:bg-slate-50 transition-all duration-300">
                Join Community
              </button>
            </div>

            <div className="mt-24 grid grid-cols-2 md:grid-cols-4 gap-12 w-full max-w-5xl">
              {[
                { label: 'Active Modules', value: modules.length.toString() },
                { label: 'Cloud Sync', value: error ? 'Offline' : 'Live' },
                { label: 'Format', value: 'UQF8' },
                { label: 'Last Update', value: 'Today' }
              ].map((stat, i) => (
                <div key={i} className="flex flex-col items-center group">
                  <span className="text-4xl font-black text-slate-900 group-hover:text-indigo-600 transition-colors">{stat.value}</span>
                  <span className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1">{stat.label}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentView === 'modules' && (
          <div className="animate-fade-in">
            <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-8">
              <div>
                <h2 className="text-4xl font-black text-slate-900 mb-3 tracking-tight">Modules</h2>
                <div className="flex items-center space-x-2 text-slate-500 font-semibold">
                  <span>Semester I</span>
                  <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
                  <span>{modules.length} Available</span>
                </div>
              </div>

              <div className="relative w-full md:w-96 group">
                <SearchIcon className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input 
                  type="text" 
                  placeholder="Search module code or title..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-14 pr-6 py-4 bg-white border border-slate-200 rounded-[1.5rem] focus:ring-4 focus:ring-indigo-50 focus:border-indigo-400 outline-none transition-all shadow-sm group-hover:shadow-md"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {filteredModules.map((module) => (
                <ModuleCard 
                  key={module.id} 
                  module={module} 
                  onClick={() => navigateTo(`#/module/${module.id}`)} 
                />
              ))}
              {filteredModules.length === 0 && (
                <div className="col-span-full py-24 text-center bg-white rounded-[2.5rem] border-2 border-dashed border-slate-100">
                  <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <SearchIcon className="text-slate-300 w-8 h-8" />
                  </div>
                  <h3 className="text-lg font-bold text-slate-800">No results found</h3>
                  <p className="text-slate-400">Try adjusting your search query</p>
                </div>
              )}
            </div>
          </div>
        )}

        {currentView === 'detail' && selectedModule && (
          <div className="animate-fade-in max-w-4xl mx-auto pb-12">
            <button 
              onClick={() => navigateTo('#/modules')}
              className="flex items-center text-slate-500 font-black text-xs uppercase tracking-widest mb-8 hover:text-indigo-600 transition-colors group"
            >
              <BackIcon className="mr-3 w-5 h-5 group-hover:-translate-x-1 transition-transform" />
              Return to Modules
            </button>

            <div className="bg-gradient-to-br from-indigo-600 via-indigo-700 to-blue-700 p-10 sm:p-16 rounded-[2.5rem] text-white shadow-2xl shadow-indigo-100 mb-10 relative overflow-hidden group">
              <div className="relative z-10">
                <span className="inline-block bg-white/20 backdrop-blur-xl px-4 py-1.5 rounded-full text-[10px] font-black tracking-widest uppercase mb-6 border border-white/10">
                  {selectedModule.code}
                </span>
                <h2 className="text-4xl sm:text-5xl font-black mb-6 leading-[1.1] tracking-tight">{selectedModule.name}</h2>
                <p className="text-indigo-50/80 text-lg max-w-2xl font-medium leading-relaxed">
                  {selectedModule.description}
                </p>
              </div>

              {/* Abstract Design Elements */}
              <div className="absolute -bottom-20 -right-20 w-80 h-80 bg-white/5 rounded-full blur-3xl pointer-events-none group-hover:scale-110 transition-transform duration-1000"></div>
              <div className="absolute top-10 right-10 w-32 h-32 border border-white/10 rounded-[2rem] rotate-12 pointer-events-none"></div>
            </div>

            <div className="bg-white rounded-[2.5rem] p-8 sm:p-10 shadow-sm border border-slate-100">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-10">
                <h3 className="text-2xl font-black text-slate-900 tracking-tight">Repository</h3>
                <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                  {['All', 'Notes', 'Past Paper'].map((type) => (
                    <button
                      key={type}
                      onClick={() => setFilterType(type as any)}
                      className={`px-6 py-2.5 rounded-xl text-xs font-black tracking-widest uppercase transition-all duration-300 ${
                        filterType === type 
                        ? 'bg-white text-indigo-600 shadow-sm scale-[1.02]' 
                        : 'text-slate-500 hover:text-slate-800'
                      }`}
                    >
                      {type === 'Past Paper' ? 'GAKA' : type}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                {filteredResources.map((file) => (
                  <div key={file.id} className="group flex flex-col sm:flex-row sm:items-center justify-between p-5 bg-[#fcfdfe] hover:bg-indigo-50/30 border border-slate-100 hover:border-indigo-100 rounded-[1.8rem] transition-all duration-300">
                    <div className="flex items-center space-x-5 mb-4 sm:mb-0">
                      <div className={`p-4 rounded-2xl flex-shrink-0 transition-transform duration-500 group-hover:rotate-[10deg] ${
                        file.type === 'Notes' 
                        ? 'bg-blue-50 text-blue-600' 
                        : 'bg-orange-50 text-orange-600'
                      }`}>
                        <FileIcon className="w-6 h-6" />
                      </div>
                      <div className="min-w-0">
                        <h4 className="font-bold text-slate-800 text-lg leading-tight truncate pr-4 group-hover:text-indigo-950 transition-colors">
                          {file.name}
                        </h4>
                        <div className="flex items-center text-[10px] text-slate-400 font-black uppercase tracking-wider mt-1.5 space-x-3">
                          <span className={`${file.type === 'Notes' ? 'text-blue-500' : 'text-orange-500'}`}>
                            {file.type === 'Notes' ? 'Lecture Notes' : 'Previous GAKA'}
                          </span>
                          {file.size !== '---' && (
                            <>
                              <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                              <span>{file.size}</span>
                            </>
                          )}
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center space-x-3">
                      <button 
                        onClick={() => handleShare(file.name)}
                        className="p-4 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-2xl transition-all shadow-sm hover:shadow active:scale-95"
                        title="Share link"
                      >
                        <ShareIcon className="w-5 h-5" />
                      </button>
                      <a 
                        href={file.driveUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex-grow sm:flex-grow-0 flex items-center justify-center space-x-2 px-8 py-4 bg-white text-indigo-600 font-black text-xs uppercase tracking-widest border border-indigo-100 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all shadow-sm hover:shadow-indigo-100 active:scale-[0.98]"
                      >
                        <DownloadIcon className="w-4 h-4" />
                        <span>Get File</span>
                      </a>
                    </div>
                  </div>
                ))}

                {filteredResources.length === 0 && (
                  <div className="py-20 text-center">
                    <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                       <FileIcon className="text-slate-300" />
                    </div>
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">No resources in this category</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-100 py-16 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-8">
          <div className="flex flex-col items-center">
            <div className="flex items-center space-x-2 mb-8">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-black text-sm">G</div>
              <span className="text-lg font-black tracking-tighter text-slate-900">GAKA</span>
            </div>

            <p className="text-slate-400 text-sm font-medium text-center max-w-md leading-relaxed mb-8">
              Empowering students at Mbeya University of Science and Technology through open academic resource sharing.
            </p>

            <div className="flex flex-wrap justify-center gap-x-8 gap-y-4 text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">
              <span className="hover:text-indigo-500 cursor-pointer transition-colors">Contact Dept</span>
              <span className="hover:text-indigo-500 cursor-pointer transition-colors">Privacy Policy</span>
              <span className="hover:text-indigo-500 cursor-pointer transition-colors">Terms of Use</span>
              <span className="hover:text-indigo-500 cursor-pointer transition-colors">Feedback</span>
            </div>

            <div className="mt-12 pt-8 border-t border-slate-50 w-full text-center">
              <p className="text-slate-300 text-[10px] font-black uppercase tracking-widest">
                &copy; {new Date().getFullYear()} MUST Computer Science Community
              </p>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Navbar } from './components/Navbar';
import { ModuleCard } from './components/ModuleCard';
import { SearchIcon, BackIcon, FileIcon, DownloadIcon, ShareIcon } from './components/Icons';
import { Module, ResourceType, AcademicFile } from './types';
import { MODULES_DATA } from './constants';

// The live Google Sheet URL provided by the user
const LIVE_CSV_URL = "https://docs.google.com/spreadsheets/d/e/2PACX-1vRn-pw2j_BMf_v--CHjpGLos3oFFAyOjrlZ8vsM0uFs4E23GPcGZ2F0tdBvRZGeg7VwZ-ZkIOpHU8zm/pub?output=csv";

const App: React.FC = () => {
  const [modules, setModules] = useState<Module[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'modules' | 'detail'>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');

  // Fetch and parse Google Sheet data
  useEffect(() => {
    const fetchData = async () => {
      try {
        setIsLoading(true);
        const response = await fetch(LIVE_CSV_URL);
        if (!response.ok) throw new Error('Could not connect to the GAKA database. Please check your connection.');

        const csvText = await response.text();
        // Split by lines and filter out empty rows
        const rows = csvText.split(/\r?\n/).filter(row => row.trim() !== "").slice(1); 

        const groupedModules: Record<string, Module> = {};

        rows.forEach((row, index) => {
          // Robust CSV split: handle commas within quotes if any exist
          const parts = row.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(val => val?.trim().replace(/^"|"$/g, ''));
          // Expected structure: moduleCode, moduleName, type, title, viewUrl, downloadUrl
          const [moduleCode, moduleName, type, title, viewUrl, downloadUrl] = parts;

          if (!moduleCode || !moduleName) return;

          if (!groupedModules[moduleCode]) {
            groupedModules[moduleCode] = {
              id: moduleCode.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, ''),
              code: moduleCode,
              name: moduleName,
              description: `Repository for ${moduleName} resources. Curated for MUST CS students.`,
              resources: []
            };
          }

          const resource: AcademicFile = {
            id: `${moduleCode}-${index}`,
            name: title || 'Resource File',
            type: (type?.toLowerCase().includes('note')) ? 'Notes' : 'Past Paper',
            driveUrl: downloadUrl || viewUrl || '#',
            size: '---' // Size not explicitly provided in CSV
          };

          groupedModules[moduleCode].resources.push(resource);
        });

        const modulesArray = Object.values(groupedModules);
        if (modulesArray.length === 0) {
           throw new Error("Synchronized but found no active modules.");
        }

        setModules(modulesArray);
        setError(null);
      } catch (err) {
        console.error("GAKA Sync Error:", err);
        setError(err instanceof Error ? err.message : 'Connection failed');
        // Fallback to local constants if fetch fails
        setModules(MODULES_DATA);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  // Sync state with URL hash for navigation
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#/modules') {
        setCurrentView('modules');
      } else if (hash.startsWith('#/module/')) {
        const moduleId = hash.split('/').pop();
        const module = modules.find(m => m.id === moduleId);
        if (module) {
          setSelectedModule(module);
          setCurrentView('detail');
        } else if (modules.length > 0) {
          setCurrentView('modules');
        }
      } else {
        setCurrentView('home');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [modules]);

  const navigateTo = (path: string) => {
    window.location.hash = path;
  };

  const filteredModules = useMemo(() => {
    return modules.filter(m => 
      m.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      m.code.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [modules, searchQuery]);

  const filteredResources = useMemo(() => {
    if (!selectedModule) return [];
    return selectedModule.resources.filter(r => 
      filterType === 'All' || r.type === filterType
    );
  }, [selectedModule, filterType]);

  const handleShare = (resourceName: string) => {
    const url = window.location.href;
    if (navigator.share) {
      navigator.share({
        title: `GAKA: ${resourceName}`,
        text: `Shared academic resource from GAKA Portal`,
        url: url,
      }).catch(() => {
        navigator.clipboard.writeText(url);
        alert('Link copied to clipboard!');
      });
    } else {
      navigator.clipboard.writeText(url);
      alert('Link copied to clipboard!');
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center space-y-8 bg-white">
        <div className="relative">
          <div className="w-20 h-20 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-black text-lg">G</div>
          </div>
        </div>
        <div className="text-center">
          <p className="text-slate-900 font-black text-2xl tracking-tight animate-pulse">Synchronizing</p>
          <p className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[10px] mt-2">Connecting to MUST Database</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#fcfdfe]">
      <Navbar />

      <main className="flex-grow container mx-auto max-w-7xl px-4 py-8 sm:px-8">
        {error && (
          <div className="mb-8 p-4 bg-red-50 border border-red-100 rounded-2xl text-red-700 text-xs font-bold flex items-center justify-between animate-fade-in">
            <span className="flex items-center">
              <span className="w-2 h-2 rounded-full bg-red-500 mr-3 animate-ping"></span>
              Live Sync Failed: Showing cached module data.
            </span>
            <button onClick={() => window.location.reload()} className="bg-white px-4 py-1.5 rounded-lg shadow-sm hover:shadow-md transition-all active:scale-95">Retry Sync</button>
          </div>
        )}

        {currentView === 'home' && (
          <div className="animate-fade-in flex flex-col items-center text-center py-16 lg:py-32">
            <div className="inline-flex items-center px-4 py-1.5 mb-8 rounded-full bg-indigo-50 border border-indigo-100 text-indigo-600 text-[10px] font-black tracking-widest uppercase shadow-sm">
              <span className="w-1.5 h-1.5 rounded-full bg-indigo-500 mr-2"></span>
              CS Department Hub
            </div>
