          </div>
        </div>
        <div className="text-center">
          <p className="text-slate-900 font-black text-2xl tracking-tight animate-pulse">Synchronizing</p>
          <p className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[10px] mt-2">Connecting to MUST Database</p>
