import React, { useState, useEffect, useMemo } from 'react';
import { Navbar } from './components/Navbar';
import { ModuleCard } from './components/ModuleCard';
import { SearchIcon, BackIcon, FileIcon, DownloadIcon, ShareIcon } from './components/Icons';
import { Module, ResourceType, AcademicFile } from './types';
import { MODULES_DATA } from './constants';

// The live Google Sheet URL provided by the user
const LIVE_CSV_URL = "https://docs.google.com/spreadsheets/d/e/2PACX-1vRn-pw2j_BMf_v--CHjpGLos3oFFAyOjrlZ8vsM0uFs4E23GPcGZ2F0tdBvRZGeg7VwZ-ZkIOpHU8zm/pub?output=csv";

const App: React.FC = () => {
  const [modules, setModules] = useState<Module[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'modules' | 'detail'>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');

  // Fetch and parse Google Sheet data
  useEffect(() => {
    const fetchData = async () => {
      try {
        setIsLoading(true);
        const response = await fetch(LIVE_CSV_URL);
        if (!response.ok) throw new Error('Could not connect to the academic portal. Please check your connection.');

        const csvText = await response.text();
        // Split by lines and filter out empty rows
        const rows = csvText.split(/\r?\n/).filter(row => row.trim() !== "").slice(1); 

        const groupedModules: Record<string, Module> = {};

        rows.forEach((row, index) => {
          // Robust CSV split: handle commas within quotes if any exist
          const parts = row.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(val => val?.trim().replace(/^"|"$/g, ''));
          // Expected structure: moduleCode, moduleName, type, title, viewUrl, downloadUrl
          const [moduleCode, moduleName, type, title, viewUrl, downloadUrl] = parts;

          if (!moduleCode || !moduleName) return;

          if (!groupedModules[moduleCode]) {
            groupedModules[moduleCode] = {
              id: moduleCode.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, ''),
              code: moduleCode,
              name: moduleName,
              description: `Repository for ${moduleName} resources. Curated for MUST CS students.`,
              resources: []
            };
          }

          const resource: AcademicFile = {
            id: `${moduleCode}-${index}`,
            name: title || 'Resource File',
            type: (type?.toLowerCase().includes('note')) ? 'Notes' : 'Past Paper',
            driveUrl: downloadUrl || viewUrl || '#',
            size: '---' // Size not explicitly provided in CSV
          };

          groupedModules[moduleCode].resources.push(resource);
        });

        const modulesArray = Object.values(groupedModules);
        if (modulesArray.length === 0) {
           throw new Error("No active modules found.");
        }

        setModules(modulesArray);
        setError(null);
      } catch (err) {
        console.error("GAKA Data Error:", err);
        setError(err instanceof Error ? err.message : 'Connection failed');
        // Fallback to local constants if fetch fails
        setModules(MODULES_DATA);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  // Sync state with URL hash for navigation
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#/modules') {
        setCurrentView('modules');
      } else if (hash.startsWith('#/module/')) {
        const moduleId = hash.split('/').pop();
        const module = modules.find(m => m.id === moduleId);
        if (module) {
          setSelectedModule(module);
          setCurrentView('detail');
        } else if (modules.length > 0) {
          setCurrentView('modules');
        }
      } else {
        setCurrentView('home');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [modules]);

  const navigateTo = (path: string) => {
    window.location.hash = path;
  };

  const filteredModules = useMemo(() => {
    return modules.filter(m => 
      m.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      m.code.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [modules, searchQuery]);

  const filteredResources = useMemo(() => {
    if (!selectedModule) return [];
    return selectedModule.resources.filter(r => 
      filterType === 'All' || r.type === filterType
    );
  }, [selectedModule, filterType]);

  /**
   * Robust copy to clipboard utility that handles permission issues by falling back
   * to the traditional document.execCommand approach if navigator.clipboard fails.
   */
  const copyToClipboard = async (text: string) => {
    try {
      // Try modern API first
      if (navigator.clipboard && window.isSecureContext) {
        await navigator.clipboard.writeText(text);
        alert('Link copied to clipboard!');
        return;
      }

      // Fallback for non-secure contexts or permission denied
      throw new Error('Clipboard API unavailable');
    } catch (err) {
      try {
        // Traditional fallback using a temporary textarea
        const textArea = document.createElement("textarea");
        textArea.value = text;

        // Ensure textarea is not visible
        textArea.style.position = "fixed";
        textArea.style.left = "-999999px";
        textArea.style.top = "-999999px";
        document.body.appendChild(textArea);

        textArea.focus();
        textArea.select();

        const successful = document.execCommand('copy');
        document.body.removeChild(textArea);

        if (successful) {
          alert('Link copied to clipboard!');
        } else {
          throw new Error('Fallback copy failed');
        }
      } catch (fallbackErr) {
        console.error('Failed to copy text: ', fallbackErr);
        // Last resort: prompt the user to copy manually
        window.prompt("Copy link to clipboard: Ctrl+C, Enter", text);
      }
    }
  };

  const handleShare = (resourceName: string) => {
    const url = window.location.href;
    if (navigator.share) {
      navigator.share({
        title: `GAKA: ${resourceName}`,
        text: `Shared academic resource from GAKA Portal`,
        url: url,
      }).catch((err) => {
        // If user cancelled, don't necessarily bother them with clipboard
        // but if it's an actual failure (not cancellation), use fallback
        if (err.name !== 'AbortError') {
          copyToClipboard(url);
        }
      });
    } else {
      copyToClipboard(url);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center space-y-8 bg-white">
        <div className="relative">
          <div className="w-20 h-20 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin"></div>
