                  <p className="text-slate-500 text-base font-normal leading-relaxed">{feature.text}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentView === 'about' && (
          <div className="animate-fade-in max-w-5xl mx-auto py-12">
