                        <span className={`text-[11px] font-bold uppercase tracking-widest mt-2 block ${file.type === 'Notes' ? 'text-emerald-500' : 'text-teal-500'}`}>
                          {file.type === 'Notes' ? 'Study Material' : 'Exam Archive'}
                        </span>
