import React, { useState, useEffect, useMemo } from 'react';
import { Navbar } from './components/Navbar';
import { ModuleCard } from './components/ModuleCard';
import { SearchIcon, BackIcon, FileIcon, DownloadIcon, ShareIcon, ChevronRightIcon, BookOpenIcon } from './components/Icons';
import { Module, ResourceType, AcademicFile } from './types';
import { MODULES_DATA } from './constants';

const LIVE_CSV_URL = "https://docs.google.com/spreadsheets/d/e/2PACX-1vRn-pw2j_BMf_v--CHjpGLos3oFFAyOjrlZ8vsM0uFs4E23GPcGZ2F0tdBvRZGeg7VwZ-ZkIOpHU8zm/pub?output=csv";

const App: React.FC = () => {
  const [modules, setModules] = useState<Module[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'modules' | 'detail' | 'about'>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');

  useEffect(() => {
    const fetchData = async () => {
      try {
        setIsLoading(true);
        const response = await fetch(LIVE_CSV_URL);
        if (!response.ok) throw new Error('Sync failed');

        const csvText = await response.text();
        const rows = csvText.split(/\r?\n/).filter(row => row.trim() !== "").slice(1); 

        const skeletonModules: Module[] = MODULES_DATA.map(m => ({
          ...m,
          resources: [] 
        }));

        rows.forEach((row, index) => {
          // Robust parsing for CSV fields
          const parts = row.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(val => val?.trim().replace(/^"|"$/g, ''));

          /**
           * Mapping refined for reliability:
           * index 0: Module Code
           * index 2: Type (Notes / Past Paper)
           * index 3: Title
           * index 4/5: Links (Drive View/Download)
           */
          const moduleCode = parts[0];
          const type = parts[2];
          const title = parts[3];

          // Resilient Link Detection: Check index 5 first, fallback to index 4 if empty
          const linkCandidate1 = parts[5];
          const linkCandidate2 = parts[4];
          const downloadUrl = (linkCandidate1 && linkCandidate1.startsWith('http')) 
            ? linkCandidate1 
            : (linkCandidate2 && linkCandidate2.startsWith('http') ? linkCandidate2 : '#');

          if (!moduleCode) return;

          const normalizedSheetCode = moduleCode.replace(/\s+/g, '').toLowerCase();

          const targetModule = skeletonModules.find(
            m => m.code.replace(/\s+/g, '').toLowerCase() === normalizedSheetCode
          );

          if (targetModule) {
            const resource: AcademicFile = {
              id: `dynamic-${index}`,
              title: title || 'Academic Resource',
              type: (type?.toLowerCase().includes('note')) ? 'Notes' : 'Past Paper',
              downloadUrl: downloadUrl,
              size: '---' 
            };
            targetModule.resources.push(resource);
          }
        });

        // Only display modules that have at least one resource in the sheet
        const activeModules = skeletonModules.filter(m => m.resources.length > 0);
        setModules(activeModules);
        setError(null);
      } catch (err) {
        console.error("Fetch Error:", err);
        setError("Synchronizing failed. No live data available.");
        setModules([]); 
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#/modules') {
        setCurrentView('modules');
      } else if (hash === '#/about') {
        setCurrentView('about');
      } else if (hash.startsWith('#/module/')) {
        const moduleId = hash.split('/').pop();
        const module = modules.find(m => m.id === moduleId);
        if (module) {
          setSelectedModule(module);
          setCurrentView('detail');
          setFilterType('All'); 
        } else if (modules.length > 0) {
          setCurrentView('modules');
        } else {
          setCurrentView('home');
        }
      } else {
        setCurrentView('home');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [modules]);

  const navigateTo = (path: string) => {
    window.location.hash = path;
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const filteredModules = useMemo(() => {
    return modules.filter(m => {
      const matchesSearch = m.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
